sql:
SELECT query_text
FROM query_plans
WHERE query_exec_time > (SELECT AVG(query_exec_time) FROM query_plans);

SELECT DISTINCT u.username
FROM users u
LEFT JOIN optimization_recommendations o ON u.user_id = o.recommended_by;

SELECT query_text, query_cost
FROM query_plans
WHERE query_cost > 100;

SELECT query_text 
FROM query_plans 
WHERE query_exec_time < (SELECT AVG(query_exec_time) FROM query_plans);

SELECT recommendation_text, is_important 
FROM optimization_recommendations
WHERE recommended_by = 1 AND is_important = 1;

SELECT query_text 
FROM query_plans 
WHERE query_cost > (SELECT AVG(query_cost) FROM query_plans);

SELECT COUNT(DISTINCT user_id) AS unique_users,
       SUM(query_exec_time) AS total_execution_time
FROM query_plans;

external_knowledge:
- 'High-impact queries' are those queries flagged for significantly affecting system performance;
- 'Whispers of the sea' refers to the query texts, representing the underlying SQL being analyzed;
- 'Treasure maps' refer to the optimization recommendation texts, indicating potential ways to improve query performance;
- 'Roughest waters' metaphorically refers to 'high-impact' tags;
- 'Ocean's purse' metaphorically refers to the total cost of execution for these high-impact queries;
- 'Treasure maps offered' refers to the count of optimization recommendations given for those queries.

